var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"제가… 태양문을 지키게 된다고요?","JPN":"私が……太陽の門を守るのですか？","ENG":"I'm... going to guard the Solar Gate?","TWN":"要我…守護太陽門嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"그렇습니다. 엘리시온의 심장과도 같은 성역을 지키는 아주 영예로운 일이죠.","JPN":"そうです。エリシオンの心臓ともいえる聖域を守る、とても名誉あることですよ。","ENG":"Yes. It is an honorable task to guard the sanctuary that is the heart of Elysion.","TWN":"是的。守護艾利森心臟般的聖域，這是非常光榮的任務。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"태양문의 위병으로서 주어진 기간을 무사히 복무한다면, 정식 팔라딘의 자격을 갖추게 될 겁니다.","JPN":"太陽の門の衛兵として与えられた期間に無事服役が終わると、正式パラディンの資格を得ることになります。","ENG":"Once you fulfill your time as the guard of the Solar Gate, you will officially become a paladin.","TWN":"作為太陽門的衛兵，如果能順利渡過規定的服役期，就能獲得正式聖騎士的資格。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"우와아…","JPN":"うわあ……","ENG":"Wow...","TWN":"哇喔…"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"꿈만 같아요. 드디어 제가 에클레시아님 같은 팔라딘이 된다니…","JPN":"夢みたいです。ようやく私がエクレシア様のようなパラディンになるなんて……","ENG":"It's like I'm dreaming. I can finally become a paladin like Her Eminence...","TWN":"簡直像做夢一樣，我終於也能成為像艾克蕾西亞主教那樣的聖騎士了…"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"이런 기회를 주셔서 감사합니다! 교구장님!","JPN":"こんな機会をくださって、ありがとうございます！　教区長！","ENG":"Thank you for this opportunity, sir!","TWN":"謝謝教區主教給我這個機會！！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"저에게 감사하지 않아도 됩니다.","JPN":"私に感謝する必要はありません。","ENG":"There is no need to thank me.","TWN":"不用特別感謝我。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"이건 제가 아니라 에클레시아님께서 특별히 부탁하신 일이니까요.","JPN":"これは私ではなく、エクレシア様から特別に頼まれたことですから。","ENG":"This was a special request from Her Eminence.","TWN":"這是艾可露西亞主教特別拜託的事情。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"아앗… 정말요?!","JPN":"わあっ……本当ですか！？","ENG":"Oh... really?!","TWN":"真…真的嗎？！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"다들 똑같이 노력했는데… 저 혼자만 이런 특혜를 누려도 괜찮은 걸까요?","JPN":"みんな一緒に頑張ったのに……私だけこんなに恵まれてもいいのでしょうか？","ENG":"But we all worked so hard... Will it be okay for me to be the only one with these kinds of privileges?","TWN":"大家都一樣努力…只有我一個人享受這樣的特權，真的可以嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"공정성을 위해 본인이 직접 추천을 철회하겠다면 막을 의사는 없습니다만…","JPN":"公正性のため、あなたが自ら推薦を撤回するというなら止める気はありませんが……","ENG":"If you wish to refuse this position out of fairness, I will not stop you, but...","TWN":"公平起見，如果你要拒絕這項任務，我也不會阻止…"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"네? 아뇨! 그럴 리가요!","JPN":"はい？　いいえ！　そんな！","ENG":"Huh? No! Of course I wouldn't!","TWN":"呃？不！怎麼會呢！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"쓸데없는 소릴 해서 죄송합니다!","JPN":"余計なことを言って申し訳ありません！","ENG":"I'm sorry for talking nonsense!","TWN":"我好像多嘴了，很抱歉！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"하하, 걱정마세요. 당신의 출중한 실력은 다들 인정하고 있으니까요.","JPN":"はは、心配しないでください。あなたの素晴らしい実力は、皆から認められています。","ENG":"Haha, no worries. Everyone recognizes your outstanding skills.","TWN":"哈哈，別擔心，大家都認可你出色的能力。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"언젠가 훌륭한 팔라딘이 되겠지만, 그 시기가 좀 더 앞당겨졌을 뿐입니다.","JPN":"いつか立派なパラディンになるでしょうが、その時期が少し早くなっただけです。","ENG":"You will become a great paladin one day, and the only thing that has changed is that your time has come a little earlier.","TWN":"你總有一天會成為傑出的聖騎士，現在只是把時間提前而已。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"앞당겨진 거라고요?","JPN":"早くなった？","ENG":"A little earlier?","TWN":"提前嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"동토의 역병이 날로 짙어지고 있어요.","JPN":"凍土の疫病が日に日にひどくなっています。","ENG":"The plague of the gelid lands is getting worse day by day.","TWN":"凍土的瘟疫日益嚴重。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"추기경들 사이에선 마왕을 서둘러 토벌해야 한다는 우려의 목소리가 날로 커져가고 있죠.","JPN":"枢機卿の間では、早急に魔王を討伐しなければという焦りの声も上がっています。","ENG":"The cardinals' concerns have grown larger and they wish to eliminate the Demon Lord as fast as possible.","TWN":"樞機主教之間，急需討伐魔王的呼聲越來越高。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"에클레시아님께선, 모드레드 자매님이 마왕 토벌에 일조하길 바라고 계시는 겁니다.","JPN":"エクレシア様は、シスターモードレッドが魔王の討伐に携わることをお望みなのです。","ENG":"Her Eminence seems to want your help in defeating the Demon Lord, Sister Mordred.","TWN":"艾可露西亞主教希望莫德雷德姐妹能在討伐魔王中有所貢獻。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"에클레시아님이… 저를…?","JPN":"エクレシア様が……私を……？","ENG":"Her Eminence... wants me...?","TWN":"艾可露西亞主教…希望我…？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"일주일 뒤, 위병교대식을 치르고 첫 근무를 서게 될 겁니다.","JPN":"一週間後、衛兵交代式を経て初勤務につくことになるでしょう。","ENG":"In a week, you will begin your first shift as the guard of the Solar Gate after the guard changing ceremony.","TWN":"一週後，將舉行衛兵交接儀式，你將開始第一次值勤。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"그러니 그 전까지 몸가짐을 바르게 하시길.","JPN":"ですから、それまで言動に気をつけてください。","ENG":"Until then, I suggest you behave yourself.","TWN":"所以在那之前，請保持端正的行為舉止。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"네, 명심하겠습니다.","JPN":"はい、肝に銘じます。","ENG":"I'll keep that in mind, sir.","TWN":"是！我明白了！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"아 참.","JPN":"あ、そうだ。","ENG":"Oh, right.","TWN":"對了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"교대식 전에 태양문을 답사하고 싶은데, 괜찮을까요?","JPN":"交代式の前に太陽の門を調査したいのですが、大丈夫でしょうか？","ENG":"Would it be okay for me to tour the Solar Gate before the ceremony?","TWN":"我想在交接儀式前勘察太陽門，可以嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HEAD_NPC_PARISH_NULL","text":{"KOREA":"그럼 함께 가지요. 분명 좋은 경험이 될 겁니다.","JPN":"それでは、ご一緒します。きっといい経験になるでしょう。","ENG":"I shall be your guide. I am certain it will be a good experience for you.","TWN":"那就一起去吧。這一定會是一次很好的經歷。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_NULL","text":{"KOREA":"네! 잘 부탁드려요!","JPN":"はい！　よろしくお願いします！","ENG":"Okay! Thank you!","TWN":"是！拜託了！"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"엄청 큰 건축물이네.","JPN":"大きな建物だね。","ENG":"It's so tall.","TWN":"真是個宏偉的建築物呢。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"눈보라가 심해서 몰랐는데, 여기 꽤 큰 도시였나봐.","JPN":"吹雪がひどくてわからなかったけど、ここって結構大きな街だったのかな。","ENG":"I didn't notice because of the snowstorm, but this city must've been pretty big.","TWN":"因為暴風雪太大沒注意到，這裡竟然是個相當大的城市。"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"응…?","JPN":"うん……？","ENG":"Hmm...?","TWN":"嗯…？"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"잠깐! 거기 들어가게?! 마물이라도 숨어있으면 어쩌려구!","JPN":"ちょっと！　そこ入るつもりなの！？　魔物が隠れていたらどうするのよ！","ENG":"Wait! You're not thinking of going in there, are you? What if there are monsters hiding inside?","TWN":"等一下！你要進去那裡嗎？！如果有怪物藏在裡面怎麼辦！"},"stage":{"bg":"COUNTERSIDE_ASH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐야. 되게 어둡네.","JPN":"うわっ。すごく暗いね。","ENG":"Whoa. It's so dark in here.","TWN":"搞什麼，好黑喔。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"이런 넓은 공간에 창문도 하나 없고. 대체 뭐하는 곳이지?","JPN":"こんな広い空間なのに、窓が一つもない。いったい何をする場所なんだろう？","ENG":"It's so spacious, but there aren't any windows. I wonder what this place was used for.","TWN":"這麼大的空間，連一扇窗戶都沒有。這裡到底是幹什麼的地方？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"안 보여요.","JPN":"見えません。","ENG":"I can't see a thing.","TWN":"看不見。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그야 이렇게 어두우니 안 보이는 게 당연…","JPN":"そりゃこんなに暗いと当然見えな……","ENG":"Of course, you can't see anything because it's this dark–","TWN":"這麼黑，看不見也是當然的…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"루? 왜 갑자기 주저앉고 그래?","JPN":"ルー？　突然座り込んでどうしたの？","ENG":"Lugh? Why are you suddenly sitting down?","TWN":"露？怎麼突然蹲下？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"좀 전에 너무 달려서 힘이 풀린 거야?","JPN":"さっき走りすぎて、力が抜けた？","ENG":"Did your legs give out from all that running earlier?","TWN":"是剛才跑得太猛，沒力了嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"황금가지가 있어야 할 태양문 안에… 아무것도 보이지 않아요.","JPN":"黄金の枝があるはずの太陽の門の中に……何もありません。","ENG":"It's because I can't see... the Golden Branch that is supposed to be inside the Solar Gate.","TWN":"什麼都看不見…本應該放著金枝的太陽門裡…什麼都沒有…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"태양문이라고…?","JPN":"太陽の門……？","ENG":"Solar Gate...?","TWN":"太陽門…？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"여기가 뭐하는 곳인지 알고 있어?","JPN":"ここが何をする場所なのか知ってるの？","ENG":"You know what this place is?","TWN":"你知道這個地方？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…네.","JPN":"……はい。","ENG":"...Yes.","TWN":"…對。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"이상하게… 여기까지 오는 길이 익숙하다고 느꼈어요.","JPN":"なんとなく……ここに辿り着くまでの道に見覚えがあったんです。","ENG":"I felt strangely familiar... with the way here.","TWN":"之前逃跑的時候…就覺得這裡的路很熟悉。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"어쩌면 여기가…","JPN":"もしかしたら、ここが……","ENG":"I think this place is…","TWN":"這裡或許是…"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"엘리시온일지도 몰라요.","JPN":"エリシオンかもしれません。","ENG":"Elysion.","TWN":"艾利森。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"말도 안돼.","JPN":"そんな。","ENG":"That's impossible.","TWN":"怎麼可能。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"루는 엘리시온에서 왔다고 했잖아. 떠나기 전에도 이렇게 엉망이었어?","JPN":"ルーはエリシオンから来たんだよね？　エリシオンってこんなにもボロボロな場所なの？","ENG":"You said that you're from Elysion. It wasn't in ruins when you left, was it?","TWN":"露，你的國家艾利森，離開之前就已經是這樣一團糟了嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"…아뇨.","JPN":"……いいえ。","ENG":"...No.","TWN":"…不。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"엘리시온은 번영한 나라였어요.","JPN":"エリシオンは繁栄した国でした。","ENG":"Elysion was a prosperous country.","TWN":"艾利森曾經是一個繁榮的國家。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"태양문의 빛이 지켜주기 때문에, 동토의 눈으로부터 안전한 곳이었죠.","JPN":"太陽の門の光が凍土の雪からエリシオンを守ってくれていたんです。","ENG":"It was a safe place from the gelid lands' snow because the light of the Solar Gate protected us.","TWN":"因為有太陽門的光芒守護，這裡是一個免受凍土之雪覆蓋的安全之地。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"하지만 여긴… 온통 눈밭인데다 사람 흔적도 안 보이잖아.","JPN":"でもここは……見渡すかぎり雪原で、人の跡も見えないよ。","ENG":"But here... It's all covered in snow and there are no traces of humans.","TWN":"但這裡…到處都是雪，連個人影都看不到。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L23_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"비슷한 장소를 착각한 게 아닐까?","JPN":"似たような場所と勘違いしてるんじゃない？","ENG":"Maybe you're confusing it with someplace similar?","TWN":"也許這裡只是個相似的地方？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"방금 전에 찾은 이 뱃지. 순례단의 팔라딘 문장이 틀림없어요.","JPN":"さっき見つけたこのバッジ。きっと巡礼団所属のパラディンの紋章です。","ENG":"And the badge that you found. It's with no doubt the paladin symbol of the pilgrimage.","TWN":"剛才找到的這個徽章，肯定是朝聖團的聖騎士徽章。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"우연이길 바랐는데… 이젠 부정할 수도 없게 되버렸네요.","JPN":"偶然であってほしかったのですが……もう認めるしかありませんね。","ENG":"I hoped it was all just a coincidence, but... now, I can't even deny it.","TWN":"本來希望是巧合…但現在，我有點無法否認了。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"DEMON_ROOT_NPC_QM","text":{"KOREA":"정말 경이롭지 않습니까?","JPN":"本当に信じがたい光景でしょう？","ENG":"Is this not astounding?","TWN":"令人驚歎，不是嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"DEMON_ROOT_NPC_QM","text":{"KOREA":"나라 하나가 하루 아침에 겨울로 뒤덮인 폐허가 되다니 말이죠.","JPN":"一国が一日で冬の廃墟になるなんて。","ENG":"Overnight, a country collapsed into snow-covered ruins.","TWN":"一個國家竟然在一夜之間變成了被冬天覆蓋的廢墟。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"마치 아발론이 몰락하던 그날처럼… 덧없군요.","JPN":"まるで、アバロンが没落したあの日のように……儚いですね。","ENG":"Just like the day when Avalon fell... in vain.","TWN":"就像阿瓦隆隕落的那天一樣…真是無常。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"악마…!","JPN":"悪魔……！","ENG":"The devil...!","TWN":"魔鬼…！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"이런. 무작정 눈앞의 것을 쏘고 보려 하다니.","JPN":"おっと。むやみに撃つと危ないですよ。","ENG":"Oh, my. Trigger-happy, much?","TWN":"盲目地瞄準眼前的東西可不好。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"사수여. 당신은 좀 더 멀리 보는 버릇을 들이는 편이 좋겠네요.","JPN":"射手。あなたはもう少し遠くを見る習慣を身につけた方が良さそうです。","ENG":"Markswoman. You must get in the habit of having some foresight.","TWN":"神槍手，你最好把目光放得更長遠些。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"죽어라앗!","JPN":"死ねぇ！","ENG":"DIE!","TWN":"去死吧！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"R":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"뭐, 뾰족머리 꼬마. 당신에게 예의따윈 기대도 하지 않았습니다.","JPN":"そうでした、トゲ頭のおチビさん。あなたに礼儀なんてものを期待してはいけませんでしたね。","ENG":"Well, I never expected much grace from you, pointy-haired kid.","TWN":"至於你，頭上長角的小鬼，我從沒指望你會有禮貌。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"누구더러 뾰족머리라는 거야! 이 호박대가리!","JPN":"誰がトゲ頭だ！　このカボチャ頭！","ENG":"Who are you calling pointy?! Pumpkin head!","TWN":"你說誰是頭上長角的小鬼！你這個南瓜頭！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"당신이… 어째서 이곳에 있는 거죠?","JPN":"あなたが……どうしてここに？","ENG":"How... are you even here?","TWN":"你…你為什麼在這裡？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"난 어디에나 존재합니다. 거기에 계약이라는 제약이 걸려있을 뿐.","JPN":"私はどこにでも存在します。そこには契約という制約があるだけ。","ENG":"I exist everywhere. With my only limitation being a contract.","TWN":"我無處不在，只是受制於契約的限制。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"마왕은 내가 이곳에 있길 원했고, 그래서 내가 이곳에 존재하는 것이죠.","JPN":"魔王は私がここにいることを望んだ。だから私はここに存在しているのです。","ENG":"The Demon Lord wanted me here, so here I am.","TWN":"魔王希望我在這裡，所以我就在這裡。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"}}}},{"id":"L44_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"마왕이 당신을 이곳으로 보냈다고요?","JPN":"魔王があなたをここに向かわせたんですか？","ENG":"The Demon Lord sent you here?","TWN":"魔王把你派到這裡來的？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_CONFUSION"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"쳇, 마왕이 우리가 여기 올 줄 알고 있었던 거야?","JPN":"ちっ、魔王はあたしたちがここに来るって知ってたの？","ENG":"Tch! Even the Demon Lord knew we were coming?","TWN":"哼，魔王也知道我們會來這裡嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"후후, 마왕은 부상을 회복하는 데 전념하고 있습니다. 당신들을 신경 쓸 리가 없죠.","JPN":"ふふ、魔王は怪我の回復に専念しています。あなたたちを気にしている暇はありません。","ENG":"Haha, the Demon Lord is focusing on recovering her wounds. She has no time to spare for you.","TWN":"呵呵，魔王正專注于恢復傷勢，根本不會在意你們。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"난 그저 죄인을 감시하라는 명령을 받았을 뿐이라서요.","JPN":"私はただ、囚人を監視するようにと命令されただけですよ。","ENG":"I was merely ordered to watch over a sinner.","TWN":"我只是奉命監視罪人而已。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"죄인이라면 설마…?","JPN":"囚人ってまさか……？","ENG":"By sinner, you mean...","TWN":"罪人…？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…그 검은 갑옷을 말하는 거야?","JPN":"……あの黒い鎧のこと？","ENG":"...the black armor?","TWN":"…你是說那個黑色的盔甲？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"공교롭게도, 내가 나서기 전에 당신들은 이미 죄수를 풀어주었더군요.","JPN":"あいにく、私が来る前にあなたたちが囚人を解放してしまいましたが。","ENG":"But unfortunately for me, you seemed to have let her free before I could do anything.","TWN":"巧合的是，在我出面之前，你們已經放走了她。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"마왕께서 알게 된다면 정말 노여워하실 겁니다.","JPN":"魔王が知れば、大そうお怒りになるでしょう。","ENG":"The Demon Lord will be furious if she finds out about this.","TWN":"如果魔王知道了，一定會非常憤怒。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그렇게 허술하게 묶어놓고선 무슨 감시를 했다는 거야?","JPN":"あんな適当に縛っておいて、何が監視だよ。","ENG":"Watching over her when you tied her up so loosely?","TWN":"戒備那麼鬆懈，算什麼監視？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"흥, 악마란 것도 별거 없네.","JPN":"フン、悪魔も大したものじゃないね。","ENG":"Hmph. Guess there's nothing to being a devil.","TWN":"哼，原來魔鬼也不過如此。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그래서, 죄수를 풀어준 우리에게 보복하려고 온 건가요?","JPN":"それで、囚人を解放した私たちに復讐しに来たんですか？","ENG":"So, you're here to get revenge on us?","TWN":"所以，你是來報復我們的嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"아뇨. 당신들을 죽이기 위해 내 하수인들을 더 이상 허비할 생각은 없습니다.","JPN":"いいえ。あなたたちを殺すために、これ以上私の手下を無駄遣いするつもりはありません。","ENG":"No, I will not waste any more of my minions trying to kill you both.","TWN":"不，我不打算再浪費我的手下來殺你們。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"지금은…","JPN":"今は……","ENG":"At least for now...","TWN":"現在…"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"그래요.","JPN":"そうですね。","ENG":"All right.","TWN":"沒錯。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"마지막 배웅이라고 해두죠.","JPN":"最後の挨拶とでも、言っておきましょう。","ENG":"This will be our last farewell, I suppose.","TWN":"就當是最後的送別吧。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"이번엔 무슨 속셈인지 모르겠지만…","JPN":"なんのつもりか知らないけど……","ENG":"I don't know what you're up to this time, but...","TWN":"雖然不知道這次你又在打什麼主意…"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"절대 뜻대론 안 될 거예요!","JPN":"絶対あなたの思いどおりにはなりません！","ENG":"you're never going to have your way!","TWN":"絕對不會如你所願的！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"그 단검은…?","JPN":"その短剣は……？","ENG":"That dagger...!","TWN":"那把匕首…？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"내 손 잡아요! 모르가나!","JPN":"私の手を握って！　モルガナ！","ENG":"Grab my hand, Morgana!","TWN":"抓住我的手！莫甘娜！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"흥, 잘 있어라! 멍청한 악마!","JPN":"フン、さよならだ！　バカ悪魔！","ENG":"Hmph! Bye, you stupid devil!","TWN":"哼，再見了！愚蠢的魔鬼！"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"피와 제기를 이용한 공간이동 주술이라…","JPN":"血と祭器を利用した空間移動の呪術か……","ENG":"A space-jumping incantation involving blood and ritual equipment...","TWN":"用血和祭器進行的空間移動嗎…"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"역시, 그녀가 살아있었나?","JPN":"やはり、彼女は生きていたのか？","ENG":"So it seems that she is still alive.","TWN":"果然，她也還活著嗎…"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"아니.","JPN":"いや。","ENG":"No.","TWN":"不。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"살아있다는 표현은 부적절할지도 모르겠군.","JPN":"生きていたという表現は不適切かもしれない。","ENG":"\\"Alive\\" might not be the proper term for her.","TWN":"用活著來形容可能不太恰當。"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"음…?","JPN":"む……？","ENG":"Mm...?","TWN":"嗯…？"},"stage":{"bg":"CORRIDOR_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_QM","text":{"KOREA":"여기에 있었구나, 후작.","JPN":"ここにいたのか、侯爵。","ENG":"There you are, Marquis.","TWN":"原來你在這裡，侯爵。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"솔리키타티오.","JPN":"ソリキタティオ。","ENG":"Sollicitatio.","TWN":"索爾奇塔提奧。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"마왕께서 당신을 보낸 겁니까?","JPN":"魔王の命令で来たのですか？","ENG":"Did the Demon Lord send you for me?","TWN":"是魔王派你來的嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"내가 너에게 질문을 허락한 적이 있었던가?","JPN":"余は貴様に質問することを許可しておらんぞ。","ENG":"Did I allow you to speak?","TWN":"我有允許你提問嗎？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"형벌을 받고 있던 죄인이 사라졌더군.","JPN":"刑罰を受けていたはずの囚人の姿がなかった。","ENG":"I see the sinner who was being punished has disappeared.","TWN":"正在受刑的罪人不見了。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"간수 일 정도는 어려운 역할이 아닐 줄 알았는데, 내 동생이 널 너무 과대평가했어.","JPN":"看守の仕事など簡単にこなせると思っていたが、余の妹が貴様を高く評価しすぎたようだ。","ENG":"I thought you could handle something as simple as being a prison guard, but perhaps my sister had too high expectations for you.","TWN":"看守這種事我原以為不難，看來是我妹妹高估你了。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"집 지키는 유령에겐 식탁보를 펄럭거리며 포크를 던지는 게 최선이죠.","JPN":"番人をする幽霊にはテーブルクロスをはためかせながらフォークを投げることが精一杯です。","ENG":"All that a houseguarding ghost can do is flap tablecloths and throw forks at intruders.","TWN":"身為一個看門的鬼，我頂多只能裝腔作勢而已。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"네 녀석이 간섭할 수 없었다는 건… 살아있는 인간이 다녀갔다는 뜻인가?","JPN":"貴様が干渉できなかったということは……生きた人間が来ていたのか？","ENG":"By saying that you could not intervene... Did humans set foot in this place?","TWN":"你無法干涉的意思是…有活人來過？"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"성흔을 가진 성자였습니다.","JPN":"聖痕を持つ聖者でした。","ENG":"She was a Helgon with a Stigmata.","TWN":"是擁有聖痕的聖者。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"이 세계에도 아직 가능성이란 게 남아있는 모양이더군요.","JPN":"この世界にもまた可能性は残っているようですね。","ENG":"So it seems that possibilities still exist in this world.","TWN":"看來這個世界還有可能性。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"오히려 잘 됐구나. 잔가지를 더듬어 내려가면 그 뿌리를 알 수 있는 법이지.","JPN":"むしろ好都合だな。小枝を辿ればかならず根に辿り着くものだから。","ENG":"How wonderful. One can find its root by tracing it back from the branch.","TWN":"那正好，順著枝葉摸索下去，總能找到根源。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"너는 이곳을 다녀간 인간의 흔적을 쫓아라.","JPN":"貴様はその人間の痕跡を追え。","ENG":"Follow the traces of the humans who visited here.","TWN":"你去追蹤那些人的蹤跡。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"그리고, 전부 남김없이 짓밟아라.","JPN":"そしてすべて、跡形もなく踏みにじれ。","ENG":"And make sure there are no survivors.","TWN":"然後，把一切都徹底摧毀。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"세계는 마왕을 적으로 간주하고 있습니다.","JPN":"世界は魔王を敵と見なしています。","ENG":"This world regards the Demon Lord as its enemy.","TWN":"世界把魔王視為敵人。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"인류의 존속을 위협하면, 마왕을 위협할 대적자가 깨어나고 말겠죠.","JPN":"人類の存続を脅かせば、魔王を脅かす敵対者が目覚めてしまうでしょう。","ENG":"If we threaten the existence of humanity, a formidable Antagonist to the Demon Lord will be awakened.","TWN":"如果威脅到人類的生存，威脅魔王的敵對者就會醒過來。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"상관없다.","JPN":"構わん。","ENG":"That is of no concern.","TWN":"沒關係。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"동생이 잃은 힘을 거의 회복했으니, 세계가 어떤 저항을 하건 종말에 이를 거야.","JPN":"妹は失った力をほとんど回復した。世界がどのように抵抗しようとも、終末は避けられまい。","ENG":"My sister has almost fully recovered her strength, so no amount of resistance in the world will be able to stop the end.","TWN":"妹妹失去的力量幾乎已經恢復了，不管這個世界怎麼反抗，終將會迎來末日。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"종말이라…","JPN":"終末ですか……","ENG":"The end...?","TWN":"末日嗎…"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"마왕께선 평생 이곳에서 당신과 지내고 싶어 하실 줄 알았는데요.","JPN":"魔王はここであなたと一生を過ごすことをお望みだと思っていたのですが。","ENG":"I was under the assumption that the Demon Lord wanted to stay here with you forever.","TWN":"我以為魔王想要一輩子都和你在這裡生活。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"인간의 영혼에 기생하는 말종 따위가 참견할 문제는 아니지.","JPN":"人間の魂に寄生するクズが口を出す問題ではない。","ENG":"That is no matter what a parasite that lives off of human souls should be concerned about.","TWN":"這不是寄生在人類靈魂上的廢物該插手的事。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SOLLICI_ADMIN_NULL_NULL","text":{"KOREA":"넌 왕의 수족으로서 그 뜻을 기꺼이 행하면 될 뿐이니까.","JPN":"貴様は王の手足として喜んでその意志捧げればよいのだ。","ENG":"You are to willingly carry out the orders of the queen's will.","TWN":"你只需作為王的手下，忠實地執行她的意志。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLLICI_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"…알겠습니다.","JPN":"……わかりました。","ENG":"...Understood.","TWN":"…明白了。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DEMON_ROOT_NPC_NULL","text":{"KOREA":"명령대로, 잔존한 인류의 안식처를 찾아내어 짓밟도록 하죠.","JPN":"ご命令どおり、生き残った人類の拠り所を探しだし、踏みにじるとしましょう。","ENG":"As you command, I shall find the remaining shelters of the humans and destroy them all.","TWN":"如你所願，我會找到殘存人類的安息之地，並將它摧毀。"},"stage":{"bg":"CORRIDOR_03","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_ROOT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};